&IsErro = false
&Mensagem.SetEmpty()
//&CbrChaTra = 'zpk_prod_ADIqfB4afnVzCKkZDKGE1Nqo'	
&MarketPlaceID = '8aec0a32736646889676c911f341768a'
For Each Order EmpCod, PesCod
	Where EmpCod = &EmpCod
	Where PesCod = &PesCod

	if PesTip = TipoPEssoa.FISICA
		&CpfCnpj = PesCpf
	Else
		&CpfCnpj = PesCnpj
	Endif
	&CpfCnpj = RetornaSoNumeros.Udp(&CpfCnpj)

	&PesZoopID = PesZoopID

	&sdtZoop_Cliente.id = ''
	if PesZoopID.IsEmpty() or PesZoopID.IsNull() //VERIFICAR SE TEM O ID POST. CASO TIVER
		//https://api.zoop.ws/v1/marketplaces/marketplace_id/buyers/search
		//VERIFICA SE EXISTE UM CLIENTE CADASTRADO POR CPF CNPJ. CASO TIVER RETORNA O ID

		&ArquivoPost = 'taxpayer_id='+&CpfCnpj.Trim()

		HostWebServiceBoletoApi.Call('',999, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor) // 999 = ZOOP
		&HttpClient.Host = &EmpWebHost //servidor
		&HttpClient.Secure = 1
		&httpclient.AddHeader(!'Content-type',!'application/json')
		&httpclient.AddHeader('authorization', 'Basic enBrX3Byb2RfQURJcWZCNGFmblZ6Q0trWkRLR0UxTnFvOg==')
		&String = 'v1/marketplaces/'+trim(&MarketPlaceID)+'/buyers/search?'+&ArquivoPost.Trim()
		//&httpclient.AddString(&ArquivoPost) NAO TEM ADDSTRING SO PARAMETROS

		csharp System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12 | System.Net.SecurityProtocolType.Tls11 | System.Net.SecurityProtocolType.Tls;
		&HttpClient.Execute('GET',&String)

		&sdtZoop_Cliente.FromJson(&HttpClient.toString())

		//padraoUsuario.Call('G', '#REGISTROZOOP_CLI1' , &WWPContext.PesCod, &EmpCod, &HttpClient.toString(), &PadDtaMod)  // Grava resultado do Post só como um LOG para Consulta

		if not &sdtZoop_Cliente.id.IsEmpty()
			&PesZoopID = &sdtZoop_Cliente.id
			PesZoopID = &PesZoopID
			Commit
		Endif
	Endif	

	if PesZoopID.IsEmpty() or PesZoopID.IsNull() //VERIFICAR SE TEM O ID POST. CASO TIVER
		&sdtZoop_Cliente.id = ''

		//https://api.zoop.ws/v1/marketplaces/&MarketPlaceID/buyers
		//CLIENTE POST NEW
		&ArquivoPost = 		'{'
		&ArquivoPost += 		'		  "first_name":"'+ trim(PesRaz) +'", '
		&ArquivoPost += 		'		  "taxpayer_id":"'+&CpfCnpj+'",'
		&ArquivoPost += 		'		  "email":"'+  '' +'",' 
		&ArquivoPost += 		'		  "address":{'
		&ArquivoPost += 		'			    "line1":"'+ PesCobLog +'", '
		&ArquivoPost += 		'			    "line2":"'+ '' +'", '
		&ArquivoPost += 		'			    "neighborhood":"'+PesCobBai+'",' 
		&ArquivoPost += 		'			    "city":"'+ PesCobCidNom +'", '
		&ArquivoPost += 		'			    "state":"'+ PesCobUfeCod +'", '
		&ArquivoPost += 		'			    "postal_code":"'+ PesCobCep +'", '
		&ArquivoPost += 		'			    "country_code":"'+'BR'+'" '
		&ArquivoPost += 		'		  }'
		&ArquivoPost += 		'		}'
		&ArquivoPost = &ArquivoPost.Replace('	', '')
		&ArquivoPost = &ArquivoPost.Replace('  ', ' ')

		HostWebServiceBoletoApi.Call('',999, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor) // 999 = ZOOP
		&HttpClient.Host = &EmpWebHost //servidor
		&HttpClient.Secure = 1
		&httpclient.AddHeader(!'Content-type',!'application/json')
		&httpclient.AddHeader('authorization', 'Basic enBrX3Byb2RfQURJcWZCNGFmblZ6Q0trWkRLR0UxTnFvOg==')
		&String = 'v1/marketplaces/'+trim(&MarketPlaceID)+'/buyers'
		&httpclient.AddString(&ArquivoPost)
		csharp System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12 | System.Net.SecurityProtocolType.Tls11 | System.Net.SecurityProtocolType.Tls;
		&HttpClient.Execute('POST',&String)

		&sdtZoop_Cliente.FromJson(&HttpClient.toString())

		if not &sdtZoop_Cliente.id.IsEmpty()
			&PesZoopID = &sdtZoop_Cliente.id
			PesZoopID = &PesZoopID
			Commit
		Endif
	Else
		//https://api.zoop.ws/v1/marketplaces/&MarketPlaceID/buyers/PesZoopID
		//CLIENTE POST UPDATE
		&ArquivoPost = 		'{'
		&ArquivoPost += 		'		  "first_name":"'+ trim(PesRaz) +'", '
		&ArquivoPost += 		'		  "taxpayer_id":"'+&CpfCnpj+'",'
		&ArquivoPost += 		'		  "email":"'+  '' +'",' 
		&ArquivoPost += 		'		  "address":{'
		&ArquivoPost += 		'			    "line1":"'+ PesCobLog +'", '
		&ArquivoPost += 		'			    "line2":"'+ '' +'", '
		&ArquivoPost += 		'			    "neighborhood":"'+PesCobBai+'",' 
		&ArquivoPost += 		'			    "city":"'+ PesCobCidNom +'", '
		&ArquivoPost += 		'			    "state":"'+ PesCobUfeCod +'", '
		&ArquivoPost += 		'			    "postal_code":"'+ PesCobCep +'", '
		&ArquivoPost += 		'			    "country_code":"'+'BR'+'" '
		&ArquivoPost += 		'		  }'
		&ArquivoPost += 		'		}'
		&ArquivoPost = &ArquivoPost.Replace('	', '')
		&ArquivoPost = &ArquivoPost.Replace('  ', ' ')

		HostWebServiceBoletoApi.Call('',999, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor) // 999 = ZOOP
		&HttpClient.Host = &EmpWebHost //servidor
		&HttpClient.Secure = 1
		&httpclient.AddHeader(!'Content-type',!'application/json')
		&httpclient.AddHeader('authorization', 'Basic enBrX3Byb2RfQURJcWZCNGFmblZ6Q0trWkRLR0UxTnFvOg==')
		&String = 'v1/marketplaces/'+trim(&MarketPlaceID)+'/buyers/'+trim(PesZoopID)
		&httpclient.AddString(&ArquivoPost)
		csharp System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12 | System.Net.SecurityProtocolType.Tls11 | System.Net.SecurityProtocolType.Tls;
		&HttpClient.Execute('PUT',&String)
	Endif

	//padraoUsuario.Call('G', '#REGISTROZOOP' , &WWPContext.PesCod, &EmpCod, &HttpClient.toString(), &PadDtaMod)  // Grava resultado do Post só como um LOG para Consulta
